function validateHtmlTags(s) {
  let stack = [];
  let tags = s.split("<");
  for (let tag of tags) {
    if (tag.includes("/")) {
      if (stack.length === 0 || stack.pop() !== tag.slice(1, -1)) return false;
    } else {
      stack.push(tag.slice(1, -1));
    }
  }
  return stack.length === 0;
}

